    rules of the format by adding more data in the distance codes. */
    for (; length >= 0; --length)
    {
        if (length == 0)
        {
            return;
        }
        if (counts[length - 1] != 0)
        {
            /* Now counts[0..length - 1] does not have trailing zeros. */
            break;
        }
    }
